using System.Collections.Immutable;
using System.Linq;
using Precept.Pipeline;

namespace Precept.Language;

/// <summary>
/// Identifies the symbol namespace the language server should search when
/// building "did you mean?" suggestions for a diagnostic.
/// </summary>
public enum SuggestionSource
{
    /// <summary>User-declared fields in the precept.</summary>
    UserFields    = 1,
    /// <summary>User-declared states in the precept.</summary>
    UserStates    = 2,
    /// <summary>User-declared events in the precept.</summary>
    UserEvents    = 3,
    /// <summary>Built-in functions from <see cref="Functions"/>.</summary>
    FunctionCatalog = 4,
}

public sealed record DiagnosticMeta(
    string             Code,
    DiagnosticStage    Stage,
    Severity           Severity,
    string             MessageTemplate,
    DiagnosticCategory Category,
    DiagnosticCode[]?  RelatedCodes       = null,
    string?            FixHint            = null,
    FaultCode?         PreventsFault      = null,
    SuggestionSource[]? SuggestionSources = null,
    string?            TriggerCondition   = null,
    string[]?          RecoverySteps      = null,
    string?            ExampleBefore      = null,
    string?            ExampleAfter       = null
);

public static class Diagnostics
{
    public static DiagnosticMeta GetMeta(DiagnosticCode code) => code switch
    {
        // ── Lex ─────────────────────────────────────────────────────────────────
        DiagnosticCode.InputTooLarge                 => new(nameof(DiagnosticCode.InputTooLarge),                 DiagnosticStage.Lex,   Severity.Error,   "This definition exceeds the 65,536-character security limit and cannot be processed",                                                  DiagnosticCategory.Safety,
            TriggerCondition: "The total character count of the precept definition text exceeds the 65,536-character security limit and cannot be processed.",
            RecoverySteps: ["Split the definition into multiple smaller precept files", "Remove unused fields, states, or comments to reduce size"],
            ExampleBefore: null,
            ExampleAfter: null),
        DiagnosticCode.UnterminatedStringLiteral      => new(nameof(DiagnosticCode.UnterminatedStringLiteral),      DiagnosticStage.Lex,   Severity.Error,   "Text value opened with \" is missing its closing quote — every \" must have a matching \"",                                              DiagnosticCategory.Structure,
            FixHint: "Add a closing \" at the end of the text value",
            TriggerCondition: "A string literal opened with a double-quote character is missing its closing double-quote before the end of the line.",
            RecoverySteps: ["Add a closing \" at the end of the string value"],
            ExampleBefore: "precept Example\nfield Name as string default \"hello",
            ExampleAfter: "precept Example\nfield Name as string default \"hello\""),
        DiagnosticCode.UnterminatedTypedConstant       => new(nameof(DiagnosticCode.UnterminatedTypedConstant),       DiagnosticStage.Lex,   Severity.Error,   "Value opened with ' is missing its closing quote — every ' must have a matching '",                                                     DiagnosticCategory.Structure,
            FixHint: "Add a closing ' at the end of the typed constant",
            TriggerCondition: "A typed constant opened with a single-quote character is missing its matching closing single-quote.",
            RecoverySteps: ["Add a closing ' at the end of the typed constant value"],
            ExampleBefore: "precept Example\nfield Tz as timezone default 'America/New_York",
            ExampleAfter: "precept Example\nfield Tz as timezone default 'America/New_York'"),
        DiagnosticCode.UnterminatedInterpolation       => new(nameof(DiagnosticCode.UnterminatedInterpolation),       DiagnosticStage.Lex,   Severity.Error,   "The {{ }} section is not closed — add a closing }} on the same line",                                                                   DiagnosticCategory.Structure,
            FixHint: "Close the interpolation expression with }",
            TriggerCondition: "A string interpolation expression opened with '{' is missing its closing '}' before the end of the line.",
            RecoverySteps: ["Add a closing } to complete the interpolation expression"],
            ExampleBefore: "precept Example\nfield Name as string optional\nfield Msg as string default \"Hello {Name\"",
            ExampleAfter: "precept Example\nfield Name as string optional\nfield Msg as string default \"Hello {Name}\""),
        DiagnosticCode.InvalidCharacter                => new(nameof(DiagnosticCode.InvalidCharacter),                DiagnosticStage.Lex,   Severity.Error,   "'{0}' is not a valid character in a precept definition — remove or replace it",                                                         DiagnosticCategory.Structure,
            TriggerCondition: "A character that is not part of the Precept source alphabet appears in the source text outside of a string or typed-constant literal.",
            RecoverySteps: ["Remove the invalid character", "If you need this character as content, place it inside a string literal"],
            ExampleBefore: "precept Example​",
            ExampleAfter: "precept Example"),
        DiagnosticCode.UnrecognizedStringEscape        => new(nameof(DiagnosticCode.UnrecognizedStringEscape),        DiagnosticStage.Lex,   Severity.Error,   "'\\{0}' is not a valid escape in a text value — use \\\" for a quote, \\\\ for a backslash, \\n for a newline, or \\t for a tab",       DiagnosticCategory.Structure,
            FixHint: "Use \\\", \\\\, \\n, or \\t as valid escape sequences in text values",
            TriggerCondition: "A backslash in a string literal is followed by a character that is not a recognized escape sequence (\\n, \\t, \\\", \\\\, {{, }}).",
            RecoverySteps: ["Replace the invalid escape with a recognized one: \\\" (quote), \\\\ (backslash), \\n (newline), \\t (tab)"],
            ExampleBefore: "precept Example\nfield Name as string default \"hello\\q world\"",
            ExampleAfter: "precept Example\nfield Name as string default \"hello world\""),
        DiagnosticCode.UnrecognizedTypedConstantEscape => new(nameof(DiagnosticCode.UnrecognizedTypedConstantEscape), DiagnosticStage.Lex,   Severity.Error,   "'\\{0}' is not a valid escape in a single-quoted value — use \\' for a quote, or \\\\ for a backslash",                                DiagnosticCategory.Structure,
            FixHint: "Use \\' or \\\\ as valid escape sequences in single-quoted values",
            TriggerCondition: "A backslash in a single-quoted typed constant is followed by a character that is not a recognized escape sequence (\\', \\\\).",
            RecoverySteps: ["Use \\' to represent a literal single-quote, or \\\\ for a backslash inside a typed constant"],
            ExampleBefore: "precept Example\nfield Tz as timezone default 'Bad\\qZone'",
            ExampleAfter: "precept Example\nfield Tz as timezone default 'America/New_York'"),
        DiagnosticCode.UnescapedBraceInLiteral         => new(nameof(DiagnosticCode.UnescapedBraceInLiteral),         DiagnosticStage.Lex,   Severity.Error,   "Use '}}}}' to include a literal }} in this value — a single }} closes an interpolation, so it must be doubled",                        DiagnosticCategory.Structure,
            FixHint: "Double the brace: write }}}} to include a literal }} in the text value",
            TriggerCondition: "A single closing curly brace '}' appears in a string literal without being doubled — a lone '}' closes an interpolation, so literal braces must be written as '}}'.",
            RecoverySteps: ["Double the closing brace: write }} to include a literal } in the text value"],
            ExampleBefore: "precept Example\nfield Msg as string default \"price }\"",
            ExampleAfter: "precept Example\nfield Msg as string default \"price }}\""),

        // ── Parse ────────────────────────────────────────────────────────────────
        DiagnosticCode.ExpectedToken              => new(nameof(DiagnosticCode.ExpectedToken),              DiagnosticStage.Parse, Severity.Error,   "Expected {0} here, but found '{1}'",                                                                                                    DiagnosticCategory.Structure,
            TriggerCondition: "The parser expected a specific token such as an identifier, keyword, or punctuation but found something different or unexpected.",
            RecoverySteps: ["Ensure the declaration keyword is spelled correctly", "Provide the required identifier or keyword in the expected position"],
            ExampleBefore: "precept\nfield Name as string optional",
            ExampleAfter: "precept Example\nfield Name as string optional"),
        DiagnosticCode.UnexpectedKeyword          => new(nameof(DiagnosticCode.UnexpectedKeyword),          DiagnosticStage.Parse, Severity.Error,   "'{0}' is a keyword and cannot be used as a value — expected an expression here",                                                        DiagnosticCategory.Structure,
            FixHint: "Use a field name, literal value, or function call instead",
            TriggerCondition: "A reserved keyword appears in a position where a value expression such as a field name, literal, or function call is expected.",
            RecoverySteps: ["Replace the keyword with a field name, string literal, or function call", "If using it as a name, choose a non-keyword identifier"],
            ExampleBefore: "precept Example\nfield Status as string default \"active\"\nrule Status == from because \"check\"",
            ExampleAfter: "precept Example\nfield Status as string default \"active\"\nrule Status == \"active\" because \"check\""),
        DiagnosticCode.NonAssociativeComparison   => new(nameof(DiagnosticCode.NonAssociativeComparison),   DiagnosticStage.Parse, Severity.Error,   "Comparisons like == and < cannot be chained — {0}",                                                                                    DiagnosticCategory.TypeSystem,
            FixHint: "Break the comparison into two separate conditions joined with 'and'",
            TriggerCondition: "Two comparison operators are chained, such as '0 <= X <= 100', which is not supported because comparisons are non-associative in Precept.",
            RecoverySteps: ["Split the chain into two conditions joined with 'and': 'X >= 0 and X <= 100'"],
            ExampleBefore: "precept Example\nfield X as number default 0\nrule 0 <= X <= 100 because \"valid range\"",
            ExampleAfter: "precept Example\nfield X as number default 0\nrule X >= 0 and X <= 100 because \"valid range\""),
        DiagnosticCode.InvalidCallTarget          => new(nameof(DiagnosticCode.InvalidCallTarget),          DiagnosticStage.Parse, Severity.Error,   "'{0}' is not callable — only function names and member access expressions can be called (e.g., 'foo.method(args)')",                    DiagnosticCategory.Structure,
            RelatedCodes: [DiagnosticCode.UndeclaredFunction],
            FixHint: "Use a built-in function name or a member access expression (e.g., 'field.property')",
            TriggerCondition: "An expression that is not a named function or member access is followed by '(' — only built-in function names and member access expressions are callable.",
            RecoverySteps: ["Use a recognized built-in function name such as min, max, abs, round, or sqrt", "Or use member access syntax: field.accessor"],
            ExampleBefore: "precept Example\nfield X as number default 0\nrule (X + 1)(0) >= 0 because \"check\"",
            ExampleAfter: "precept Example\nfield X as number default 0\nrule abs(X + 1) >= 0 because \"check\""),
        DiagnosticCode.MutuallyExclusiveQualifiers => new(nameof(DiagnosticCode.MutuallyExclusiveQualifiers), DiagnosticStage.Type, Severity.Error,  "'in' and 'of' qualifiers cannot both appear on this type — only 'price' supports both",                                                DiagnosticCategory.TypeSystem,
            RelatedCodes: [DiagnosticCode.QualifierMismatch],
            FixHint: "Use 'in' for currency, 'of' for unit, or both only on 'price' types",
            TriggerCondition: "Both 'in' and 'of' qualifiers appear on a field type that does not support both — only 'price' fields accept both qualifiers simultaneously.",
            RecoverySteps: ["Use 'in' for money fields", "Use 'of' for quantity fields", "Use both only on 'price' fields"],
            ExampleBefore: "precept Example\nfield Amount as money in 'USD' of 'kg'",
            ExampleAfter: "precept Example\nfield Amount as money in 'USD'"),
        DiagnosticCode.OmitDoesNotSupportGuard    => new(nameof(DiagnosticCode.OmitDoesNotSupportGuard),    DiagnosticStage.Parse, Severity.Error,   "'omit' is an unconditional structural exclusion — 'when' guards are not allowed",                                                       DiagnosticCategory.Structure,
            FixHint: "Remove the 'when' guard. If you need conditional visibility, use 'modify Field readonly when Guard' instead",
            TriggerCondition: "A 'when' guard is attached to an 'omit' declaration — omit is an unconditional structural exclusion and cannot be conditionally applied.",
            RecoverySteps: ["Remove the 'when' guard from the omit declaration", "If conditional visibility is needed, use 'in State modify Field readonly when Guard' instead"],
            ExampleBefore: "precept Example\nfield Notes as string optional\nstate Draft initial\nstate Done terminal\nevent Complete\nomit Notes in Draft when Notes is set\nfrom Draft on Complete -> transition Done",
            ExampleAfter: "precept Example\nfield Notes as string optional\nstate Draft initial\nstate Done terminal\nevent Complete\nomit Notes in Draft\nfrom Draft on Complete -> transition Done"),
        DiagnosticCode.EventHandlerDoesNotSupportGuard => new(nameof(DiagnosticCode.EventHandlerDoesNotSupportGuard), DiagnosticStage.Parse, Severity.Error, "Event handlers ('on Event -> action') do not support 'when' guards — guards are only valid on event ensures and transition rows",       DiagnosticCategory.Structure,
            FixHint: "Remove the 'when' guard, or use 'on Event ensure Condition because Message' for guarded event logic",
            TriggerCondition: "A 'when' guard is attached to an event handler action in a stateless precept — event handler actions cannot be conditioned with a when guard.",
            RecoverySteps: ["Remove the 'when' guard from the event handler", "Use 'on Event ensure Condition because Message' for pre-event checks instead"],
            ExampleBefore: "precept Example\nfield Name as string optional\nevent SetName(N as string)\non SetName when SetName.N != \"\" -> set Name = SetName.N",
            ExampleAfter: "precept Example\nfield Name as string optional\nevent SetName(N as string)\non SetName -> set Name = SetName.N"),
        DiagnosticCode.PreEventGuardNotAllowed    => new(nameof(DiagnosticCode.PreEventGuardNotAllowed),    DiagnosticStage.Parse, Severity.Error,   "A 'when' guard before the event target is not supported on transition rows — place the guard after 'on Event'",                         DiagnosticCategory.Structure,
            FixHint: "Move the 'when' clause to after the event name: 'from State on Event when Guard'",
            TriggerCondition: "A 'when' guard appears before the event name in a transition row — guards must appear after the event name.",
            RecoverySteps: ["Move the 'when' clause to after the event name: 'from State on Event when Guard'"],
            ExampleBefore: "precept Example\nfield Active as boolean default false\nstate Draft initial\nstate Done terminal\nevent Complete\nfrom Draft when Active on Complete -> transition Done",
            ExampleAfter: "precept Example\nfield Active as boolean default false\nstate Draft initial\nstate Done terminal\nevent Complete\nfrom Draft on Complete when Active -> transition Done"),
        DiagnosticCode.ExpectedOutcome            => new(nameof(DiagnosticCode.ExpectedOutcome),            DiagnosticStage.Parse, Severity.Error,   "Expected a transition outcome ('-> transition State', '-> no transition', or '-> reject Message') but none was found",                 DiagnosticCategory.Structure,
            FixHint: "Add an outcome at the end of the transition row: '-> transition TargetState', '-> no transition', or '-> reject \"reason\"'",
            TriggerCondition: "A transition row ends without an outcome declaration — every transition row must conclude with '-> transition State', '-> no transition', or '-> reject \"message\"'.",
            RecoverySteps: ["Add '-> transition TargetState' to move to another state", "Or '-> no transition' to stay in the current state", "Or '-> reject \"reason\"' to fail the event"],
            ExampleBefore: "precept Example\nfield X as number default 0\nstate Draft initial\nstate Done terminal\nevent Complete\nfrom Draft on Complete -> set X = 1",
            ExampleAfter: "precept Example\nfield X as number default 0\nstate Draft initial\nstate Done terminal\nevent Complete\nfrom Draft on Complete -> set X = 1 -> transition Done"),
        DiagnosticCode.AssignmentInExpressionContext => new(
            nameof(DiagnosticCode.AssignmentInExpressionContext),
            DiagnosticStage.Parse,
            Severity.Error,
            "'=' is assignment and cannot be used inside an expression — use '==' for equality",
            DiagnosticCategory.Structure,
            FixHint: "Replace '=' with '==' when you mean to compare two values",
            TriggerCondition: "The assignment token '=' appears inside an expression such as a rule, ensure, guard, or computed field. In Precept, '=' is only valid in 'set' actions; comparisons use '=='.",
            RecoverySteps: ["Replace '=' with '==' for equality comparison", "Use '=' only in '-> set Field = Value' actions"],
            ExampleBefore: "precept Example\nin Listed ensure QuantityOnHand = '0 each' because \"check\"",
            ExampleAfter: "precept Example\nin Listed ensure QuantityOnHand == '0 each' because \"check\""),

        // ── Type ─────────────────────────────────────────────────────────────────
        DiagnosticCode.UndeclaredField                => new(nameof(DiagnosticCode.UndeclaredField),                DiagnosticStage.Type,  Severity.Error,   "Field '{0}' is not declared",                                                                                                          DiagnosticCategory.Naming,
            RelatedCodes: [DiagnosticCode.DuplicateFieldName],
            FixHint: "Declare the field at the top of the precept using 'field Name as Type'",
            PreventsFault: FaultCode.UndeclaredField,
            SuggestionSources: [SuggestionSource.UserFields],
            TriggerCondition: "An expression or action references a field name that has not been declared with 'field Name as Type' in the precept.",
            RecoverySteps: ["Declare the field at the top of the precept: 'field FieldName as Type'", "Check for typos — identifiers are case-sensitive"],
            ExampleBefore: "precept Example\nrule Amount >= 0 because \"positive\"",
            ExampleAfter: "precept Example\nfield Amount as number default 0\nrule Amount >= 0 because \"positive\""),
        DiagnosticCode.TypeMismatch                   => new(nameof(DiagnosticCode.TypeMismatch),                   DiagnosticStage.Type,  Severity.Error,   "Expected a {0} value here, but got '{1}'",                                                                                             DiagnosticCategory.TypeSystem,
            RelatedCodes: [DiagnosticCode.NullInNonNullableContext],
            PreventsFault: FaultCode.TypeMismatch,
            TriggerCondition: "An expression produces a value of one type but a context expects a different type.",
            RecoverySteps: ["Ensure both sides of a comparison or assignment have compatible types", "Use a literal that matches the field's declared type"],
            ExampleBefore: "precept Example\nfield X as number default 0\nrule X == \"zero\" because \"check\"",
            ExampleAfter: "precept Example\nfield X as number default 0\nrule X == 0 because \"check\""),
        DiagnosticCode.NullInNonNullableContext       => new(nameof(DiagnosticCode.NullInNonNullableContext),       DiagnosticStage.Type,  Severity.Error,   "'{0}' requires a value and cannot be empty here",                                                                                      DiagnosticCategory.TypeSystem,
            RelatedCodes: [DiagnosticCode.TypeMismatch],
            FixHint: "Add the 'optional' modifier to the field declaration to allow null values",
            PreventsFault: FaultCode.UnexpectedNull,
            TriggerCondition: "An optional field is used in a context that requires a guaranteed non-null value without a prior 'is set' guard.",
            RecoverySteps: ["Add 'when Field is set' as a guard before accessing the optional field", "Or remove 'optional' from the field declaration", "Or provide a 'default' value so the field is never null"],
            ExampleBefore: "precept Example\nfield X as number optional\nfield Y as number default 0\nstate Draft initial\nstate Done terminal\nevent Complete\nfrom Draft on Complete -> set Y = X -> transition Done",
            ExampleAfter: "precept Example\nfield X as number optional\nfield Y as number default 0\nstate Draft initial\nstate Done terminal\nevent Complete\nfrom Draft on Complete when X is set -> set Y = X -> transition Done\nfrom Draft on Complete -> transition Done"),
        DiagnosticCode.InvalidMemberAccess            => new(nameof(DiagnosticCode.InvalidMemberAccess),            DiagnosticStage.Type,  Severity.Error,   "'.{0}' is not available on {1} fields",                                                                                                DiagnosticCategory.TypeSystem,
            FixHint: "Check the available accessors for this type in the language reference",
            PreventsFault: FaultCode.InvalidMemberAccess,
            TriggerCondition: "A member accessor such as '.year', '.count', or '.currency' is used on a field type that does not expose that accessor.",
            RecoverySteps: ["Check the available accessors for this type in the language reference", "Use 'precept_types' to see which accessors are valid for each type"],
            ExampleBefore: "precept Example\nfield Amount as number default 0\nrule Amount.year > 2020 because \"check\"",
            ExampleAfter: "precept Example\nfield Amount as number default 0\nrule Amount > 0 because \"positive\""),
        DiagnosticCode.FunctionArityMismatch          => new(nameof(DiagnosticCode.FunctionArityMismatch),          DiagnosticStage.Type,  Severity.Error,   "'{0}' takes {1} inputs, but {2} were provided",                                                                                        DiagnosticCategory.TypeSystem,
            RelatedCodes: [DiagnosticCode.FunctionArgConstraintViolation],
            PreventsFault: FaultCode.FunctionArityMismatch,
            TriggerCondition: "A built-in function is called with the wrong number of arguments.",
            RecoverySteps: ["Provide exactly the required number of arguments", "Use 'precept_syntax' to see the correct parameter count for built-in functions"],
            ExampleBefore: "precept Example\nfield X as number default 0\nfield Y as number default 0\nrule min(X, Y, 0) >= 0 because \"check\"",
            ExampleAfter: "precept Example\nfield X as number default 0\nfield Y as number default 0\nrule min(X, Y) >= 0 because \"check\""),
        DiagnosticCode.FunctionArgConstraintViolation => new(nameof(DiagnosticCode.FunctionArgConstraintViolation), DiagnosticStage.Type,  Severity.Error,   "Argument {0} to '{1}' is not valid — {2}",                                                                                          DiagnosticCategory.TypeSystem,
            RelatedCodes: [DiagnosticCode.FunctionArityMismatch],
            PreventsFault: FaultCode.FunctionArgConstraintViolation,
            TriggerCondition: "An argument passed to a built-in function violates that function's parameter constraint.",
            RecoverySteps: ["Check the constraint for this function's parameter position", "Ensure the value satisfies the constraint"],
            ExampleBefore: "precept Example\nfield X as number default 0\nrule round(X, -1) == 0 because \"check\"",
            ExampleAfter: "precept Example\nfield X as number default 0\nrule round(X, 2) == 0 because \"check\""),
        DiagnosticCode.DuplicateFieldName             => new(nameof(DiagnosticCode.DuplicateFieldName),             DiagnosticStage.Type,  Severity.Error,   "Field '{0}' is already declared",                                                                                                      DiagnosticCategory.Naming,
            RelatedCodes: [DiagnosticCode.DuplicateStateName, DiagnosticCode.DuplicateEventName],
            FixHint: "Rename one of the fields to a unique name",
            TriggerCondition: "Two field declarations in the same precept use the same name.",
            RecoverySteps: ["Rename one of the fields to a unique name"],
            ExampleBefore: "precept Example\nfield Name as string optional\nfield Name as string optional",
            ExampleAfter: "precept Example\nfield FirstName as string optional\nfield LastName as string optional"),
        DiagnosticCode.DuplicateStateName             => new(nameof(DiagnosticCode.DuplicateStateName),             DiagnosticStage.Type,  Severity.Error,   "State '{0}' is already declared",                                                                                                      DiagnosticCategory.Naming,
            RelatedCodes: [DiagnosticCode.DuplicateFieldName, DiagnosticCode.DuplicateEventName],
            FixHint: "Rename one of the states to a unique name",
            TriggerCondition: "Two state declarations in the same precept use the same name.",
            RecoverySteps: ["Rename one of the states to a unique name"],
            ExampleBefore: "precept Example\nstate Draft initial\nstate Draft terminal\nevent Complete\nfrom Draft on Complete -> transition Draft",
            ExampleAfter: "precept Example\nstate Draft initial\nstate Done terminal\nevent Complete\nfrom Draft on Complete -> transition Done"),
        DiagnosticCode.DuplicateEventName             => new(nameof(DiagnosticCode.DuplicateEventName),             DiagnosticStage.Type,  Severity.Error,   "Event '{0}' is already declared",                                                                                                      DiagnosticCategory.Naming,
            RelatedCodes: [DiagnosticCode.DuplicateFieldName, DiagnosticCode.DuplicateStateName],
            FixHint: "Rename one of the events to a unique name",
            TriggerCondition: "Two event declarations in the same precept use the same name.",
            RecoverySteps: ["Rename one of the events to a unique name"],
            ExampleBefore: "precept Example\nstate Draft initial\nstate Done terminal\nevent Complete\nevent Complete\nfrom Draft on Complete -> transition Done",
            ExampleAfter: "precept Example\nstate Draft initial\nstate Done terminal\nevent Complete\nfrom Draft on Complete -> transition Done"),
        DiagnosticCode.DuplicateArgName               => new(nameof(DiagnosticCode.DuplicateArgName),               DiagnosticStage.Type,  Severity.Error,   "Argument '{0}' is already declared on event '{1}'",                                                                                    DiagnosticCategory.Naming,
            FixHint: "Rename one of the event arguments to a unique name",
            TriggerCondition: "Two arguments on the same event declaration use the same name.",
            RecoverySteps: ["Rename one of the event arguments to a unique name"],
            ExampleBefore: "precept Example\nstate Draft initial\nstate Done terminal\nevent Submit(Name as string, Name as string)\nfrom Draft on Submit -> transition Done",
            ExampleAfter: "precept Example\nstate Draft initial\nstate Done terminal\nevent Submit(FirstName as string, LastName as string)\nfrom Draft on Submit -> transition Done"),
        DiagnosticCode.UndeclaredState                => new(nameof(DiagnosticCode.UndeclaredState),                DiagnosticStage.Type,  Severity.Error,   "State '{0}' is not declared",                                                                                                          DiagnosticCategory.Naming,
            RelatedCodes: [DiagnosticCode.UndeclaredEvent, DiagnosticCode.UndeclaredField],
            FixHint: "Declare the state using 'state StateName' before referencing it",
            SuggestionSources: [SuggestionSource.UserStates],
            TriggerCondition: "A transition row references a state name that has not been declared with 'state StateName' in the precept.",
            RecoverySteps: ["Declare the state before referencing it: 'state StateName'", "Check for typos — state names are case-sensitive"],
            ExampleBefore: "precept Example\nstate Draft initial\nevent Complete\nfrom Draft on Complete -> transition Done",
            ExampleAfter: "precept Example\nstate Draft initial\nstate Done terminal\nevent Complete\nfrom Draft on Complete -> transition Done"),
        DiagnosticCode.StateListContainsWildcard      => new(nameof(DiagnosticCode.StateListContainsWildcard),      DiagnosticStage.Type,  Severity.Error,   "State list cannot mix named states with 'any' wildcard — use either 'any' or specific state names",                             DiagnosticCategory.Structure,
            FixHint: "Use either 'any' by itself or a comma-separated list of specific state names",
            TriggerCondition: "A comma-delimited state target mixes the 'any' wildcard with one or more named states.",
            RecoverySteps: ["Use 'any' alone to target every state", "Or remove 'any' and keep only the specific state names you want"],
            ExampleBefore: "precept Example\nstate Draft initial\nstate Submitted\nevent Submit\nfrom Draft, any on Submit -> transition Submitted",
            ExampleAfter: "precept Example\nstate Draft initial\nstate Submitted\nevent Submit\nfrom any on Submit -> transition Submitted"),
        DiagnosticCode.DuplicateStateInList           => new(nameof(DiagnosticCode.DuplicateStateInList),           DiagnosticStage.Type,  Severity.Warning, "State name '{0}' appears more than once in the state list",                                                             DiagnosticCategory.Structure,
            FixHint: "Remove the repeated state name from the list",
            TriggerCondition: "The same state name appears multiple times in a comma-delimited state target list.",
            RecoverySteps: ["Remove the repeated state name so each state appears only once in the list"],
            ExampleBefore: "precept Example\nstate Draft initial\nevent Submit\nfrom Draft, Draft on Submit -> transition Draft",
            ExampleAfter: "precept Example\nstate Draft initial\nevent Submit\nfrom Draft on Submit -> transition Draft"),
        DiagnosticCode.OmittedFieldReadInState        => new(nameof(DiagnosticCode.OmittedFieldReadInState),        DiagnosticStage.Type,  Severity.Error,   "Field '{0}' is omitted in state '{1}' and cannot be read in this expression",                                            DiagnosticCategory.Structure,
            FixHint: "Remove the reference to '{0}', or remove the omit declaration for '{0}' in state '{1}'",
            TriggerCondition: "An expression in a state-anchored context (guard, ensure, state action) reads a field that is omit in the anchored state.",
            RecoverySteps: ["Remove the field reference from this expression", "Remove 'in {State} omit {Field}' if the field should be accessible in this state"]),
        DiagnosticCode.OmittedFieldSetInTargetState   => new(nameof(DiagnosticCode.OmittedFieldSetInTargetState),   DiagnosticStage.Type,  Severity.Error,   "Field '{0}' is omitted in target state '{1}'; this transition cannot set it",                                              DiagnosticCategory.Structure,
            FixHint: "Remove the 'set {0}' action, or remove the omit declaration for '{0}' in state '{1}'",
            TriggerCondition: "A set action in a transition or on-entry hook targets a field that is omit in the target state.",
            RecoverySteps: ["Remove the set action — the field is structurally absent in the target state", "Remove 'in {State} omit {Field}' if the field should be settable in this state"]),
        DiagnosticCode.RequiredFieldUnassignedOnEntry => new(nameof(DiagnosticCode.RequiredFieldUnassignedOnEntry), DiagnosticStage.Type,  Severity.Error,   "Required field '{0}' is omitted in '{1}' but present in '{2}'; add `set {0} = ...` to this transition",                          DiagnosticCategory.Structure,
            RelatedCodes: [DiagnosticCode.InitialEventMissingAssignments],
            FixHint: "Add 'set {0} = <value>' to the transition action chain, or add 'in {2} omit {0}' to keep it absent, or add 'default <value>' to the field declaration",
            TriggerCondition: "A transition moves a required field (non-optional, no default, not computed) from omit (from-state) to non-omit (to-state) without a set action assigning it.",
            RecoverySteps: ["Add 'set {Field} = <value>' to the transition action chain", "Add 'in {TargetState} omit {Field}' if the field should remain absent", "Add 'default <value>' to the field declaration", "Mark the field 'optional' if absence is valid"]),
