            RecoverySteps: ["Move the event argument reference into the correct event scope", "Store the value in a field first if it needs to be used later"],
            ExampleBefore: "precept Example\nfield Name as string optional\nstate Draft initial\nstate Done terminal\nevent Submit(N as string)\nevent Complete\nrule Submit.N != \"\" because \"name required\"\nfrom Draft on Complete -> transition Done",
            ExampleAfter: "precept Example\nfield Name as string optional\nstate Draft initial\nstate Done terminal\nevent Submit(N as string)\nevent Complete\non Submit ensure Submit.N != \"\" because \"name required\"\nfrom Draft on Submit -> set Name = Submit.N -> no transition\nfrom Draft on Complete -> transition Done"),
        DiagnosticCode.InvalidInterpolationCoercion   => new(nameof(DiagnosticCode.InvalidInterpolationCoercion),   DiagnosticStage.Type,  Severity.Error,   "A {0} value cannot appear inside a text interpolation",                                                                                DiagnosticCategory.TypeSystem,
            FixHint: "Convert this value to text before interpolating, or remove it from the text literal",
            TriggerCondition: "A value of a type that cannot be converted to text is embedded in a string interpolation expression.",
            RecoverySteps: ["Remove the non-text value from the interpolation", "Or convert it to a text representation before interpolating"],
            ExampleBefore: "precept Example\nfield Items as set of string\nfield Msg as string default \"Items: {Items}\"",
            ExampleAfter: "precept Example\nfield Items as set of string\nfield Msg as string default \"active\""),
        DiagnosticCode.UnresolvedTypedConstant        => new(nameof(DiagnosticCode.UnresolvedTypedConstant),        DiagnosticStage.Type,  Severity.Error,   "Cannot determine the type of '{0}' — the content does not match any known value pattern",                                             DiagnosticCategory.TypeSystem,
            FixHint: "Place this constant where the type is unambiguous, such as in a typed field assignment",
            TriggerCondition: "A single-quoted typed constant appears where the surrounding context provides no type information to resolve its meaning.",
            RecoverySteps: ["Place the typed constant in a position where the type is clear", "Or replace it with a literal of a known type"],
            ExampleBefore: "precept Example\nfield X as number default 0\nrule X == 'something' because \"check\"",
            ExampleAfter: "precept Example\nfield X as number default 0\nrule X == 0 because \"check\""),
        DiagnosticCode.InvalidTypedConstantContent    => new(nameof(DiagnosticCode.InvalidTypedConstantContent),    DiagnosticStage.Type,  Severity.Error,   "'{0}' is not a valid {1} — check the expected format for {1} values",                                                                  DiagnosticCategory.TypeSystem,
            TriggerCondition: "A typed constant contains content that is not a valid value for the type determined from context.",
            RecoverySteps: ["Use the correct format for this type's constants", "For durations use values like '4 hours' or '30 minutes'"],
            ExampleBefore: "precept Example\nfield D as duration default 'invalid-value'",
            ExampleAfter: "precept Example\nfield D as duration default '4 hours'"),
        DiagnosticCode.DefaultForwardReference        => new(nameof(DiagnosticCode.DefaultForwardReference),        DiagnosticStage.Type,  Severity.Error,   "Computed expression for '{0}' cannot reference '{1}', which is declared later",                                                         DiagnosticCategory.Structure,
            FixHint: "Reorder field declarations so the referenced field appears before the one with the default",
            TriggerCondition: "A field's default value expression references another field that is declared later in the precept.",
            RecoverySteps: ["Reorder field declarations so referenced fields appear first"],
            ExampleBefore: "precept Example\nfield Y as number default X\nfield X as number default 0",
            ExampleAfter: "precept Example\nfield X as number default 0\nfield Y as number default X"),

        // ── Type (temporal) ──────────────────────────────────────────────────────
        DiagnosticCode.InvalidDateValue               => new(nameof(DiagnosticCode.InvalidDateValue),               DiagnosticStage.Type,  Severity.Error,   "Invalid date: {0} does not exist",                                                                                                     DiagnosticCategory.Temporal,
            RelatedCodes: [DiagnosticCode.InvalidDateFormat],
            FixHint: "Check that the day, month, and year form a valid calendar date",
            TriggerCondition: "A date constant contains a calendar date that does not exist.",
            RecoverySteps: ["Verify that the day, month, and year form a real calendar date", "Use a valid date such as '2024-02-28'"],
            ExampleBefore: "precept Example\nfield D as date default '2024-02-30'",
            ExampleAfter: "precept Example\nfield D as date default '2024-02-28'"),
        DiagnosticCode.InvalidDateFormat              => new(nameof(DiagnosticCode.InvalidDateFormat),              DiagnosticStage.Type,  Severity.Error,   "Dates must be written as YYYY-MM-DD. Use '{0}'",                                                                                       DiagnosticCategory.Temporal,
            RelatedCodes: [DiagnosticCode.InvalidDateValue, DiagnosticCode.InvalidTimeValue, DiagnosticCode.InvalidInstantFormat],
            TriggerCondition: "A date constant is not written in the required YYYY-MM-DD format.",
            RecoverySteps: ["Write dates as YYYY-MM-DD", "Do not use slashes, dots, or other separators"],
            ExampleBefore: "precept Example\nfield D as date default '15-01-2024'",
            ExampleAfter: "precept Example\nfield D as date default '2024-01-15'"),
        DiagnosticCode.InvalidTimeValue               => new(nameof(DiagnosticCode.InvalidTimeValue),               DiagnosticStage.Type,  Severity.Error,   "Invalid time: {0} must be 0\u201323 for hours, 0\u201359 for minutes and seconds",                                                     DiagnosticCategory.Temporal,
            RelatedCodes: [DiagnosticCode.InvalidDateFormat, DiagnosticCode.InvalidInstantFormat],
            FixHint: "Use hours 0–23 and minutes/seconds 0–59",
            TriggerCondition: "A time constant contains out-of-range values — hours must be 0–23 and minutes or seconds must be 0–59.",
            RecoverySteps: ["Use hours 0–23 and minutes or seconds 0–59", "Example: '14:30:00' for 2:30 PM"],
            ExampleBefore: "precept Example\nfield T as time default '25:00:00'",
            ExampleAfter: "precept Example\nfield T as time default '14:30:00'"),
        DiagnosticCode.InvalidInstantFormat           => new(nameof(DiagnosticCode.InvalidInstantFormat),           DiagnosticStage.Type,  Severity.Error,   "Instants must end with Z to indicate UTC. Use '{0}Z'",                                                                                  DiagnosticCategory.Temporal,
            RelatedCodes: [DiagnosticCode.InvalidDateFormat, DiagnosticCode.InvalidTimeValue],
            TriggerCondition: "An instant constant does not end with 'Z' to indicate UTC — all Precept instant values are in UTC and require the Z suffix.",
            RecoverySteps: ["Append 'Z' at the end of the instant value: '2024-01-15T14:30:00Z'"],
            ExampleBefore: "precept Example\nfield I as instant default '2024-01-15T14:30:00'",
            ExampleAfter: "precept Example\nfield I as instant default '2024-01-15T14:30:00Z'"),
        DiagnosticCode.InvalidTimezoneId              => new(nameof(DiagnosticCode.InvalidTimezoneId),              DiagnosticStage.Type,  Severity.Error,   "'{0}' is not a recognized timezone — use canonical IANA form like 'America/New_York'",                                                  DiagnosticCategory.Temporal,
            FixHint: "Use a canonical IANA timezone ID such as 'America/New_York' or 'Europe/London'",
            TriggerCondition: "A timezone constant contains an identifier that is not a recognized IANA timezone name.",
            RecoverySteps: ["Use a canonical IANA timezone identifier such as 'America/New_York', 'Europe/London', or 'UTC'"],
            ExampleBefore: "precept Example\nfield Tz as timezone default 'US/East'",
            ExampleAfter: "precept Example\nfield Tz as timezone default 'America/New_York'"),
        DiagnosticCode.UnqualifiedPeriodArithmetic    => new(nameof(DiagnosticCode.UnqualifiedPeriodArithmetic),    DiagnosticStage.Type,  Severity.Error,   "Period field '{0}' may contain {1} components — use period of '{2}' to constrain it",                                                  DiagnosticCategory.Temporal,
            RelatedCodes: [DiagnosticCode.MissingTemporalUnit],
            FixHint: "Add 'period of DimensionUnit' to constrain the period to a single unit",
            TriggerCondition: "Period arithmetic is performed on a period field that has no 'of' dimension qualifier.",
            RecoverySteps: ["Add a dimension qualifier to the period field", "Or use a duration field instead for fixed-length time spans"],
            ExampleBefore: "precept Example\nfield Elapsed as period\nfield Extra as period default '7 days'\nfield Total as period <- Elapsed + Extra",
            ExampleAfter: "precept Example\nfield Elapsed as period of 'days'\nfield Extra as period of 'days' default '7 days'\nfield Total as period of 'days' <- Elapsed + Extra"),
        DiagnosticCode.MissingTemporalUnit            => new(nameof(DiagnosticCode.MissingTemporalUnit),            DiagnosticStage.Type,  Severity.Error,   "A bare number doesn't specify a unit. Use '{0}' + '{1}' to add {1}",                                                                   DiagnosticCategory.Temporal,
            RelatedCodes: [DiagnosticCode.UnqualifiedPeriodArithmetic],
            FixHint: "Add a temporal unit keyword after the number, such as 'days' or 'hours'",
            TriggerCondition: "A bare number is used in a temporal context where a unit keyword such as 'days', 'hours', or 'months' is required.",
            RecoverySteps: ["Add a temporal unit keyword after the number"],
            ExampleBefore: "precept Example\nfield D as duration default '5'",
            ExampleAfter: "precept Example\nfield D as duration default '5 hours'"),
        DiagnosticCode.FractionalUnitValue            => new(nameof(DiagnosticCode.FractionalUnitValue),            DiagnosticStage.Type,  Severity.Error,   "Unit values must be whole numbers. Use smaller units for fractions: '{0}'",                                                             DiagnosticCategory.Temporal,
            FixHint: "Use a smaller unit (e.g., 'minutes' instead of 'hours') to avoid fractional values",
            TriggerCondition: "A temporal unit value contains a fractional non-integer quantity — temporal units must be whole numbers.",
            RecoverySteps: ["Use a whole number, or convert to smaller units"],
            ExampleBefore: "precept Example\nfield D as duration default '1.5 hours'",
            ExampleAfter: "precept Example\nfield D as duration default '90 minutes'"),

        // ── Type (collection safety) ─────────────────────────────────────────────
        DiagnosticCode.UnguardedCollectionAccess      => new(nameof(DiagnosticCode.UnguardedCollectionAccess),      DiagnosticStage.Type,  Severity.Error,   "'{0}' may be empty — guard with if {0}.count > 0 before accessing .{1}",                                                               DiagnosticCategory.Safety,
            RelatedCodes: [DiagnosticCode.UnguardedCollectionMutation],
            FixHint: "Add 'when CollectionField.count > 0' to the guard before accessing this member",
            PreventsFault: FaultCode.CollectionEmptyOnAccess,
            TriggerCondition: "A collection accessor that requires a non-empty collection is used without a preceding non-empty guard.",
            RecoverySteps: ["Add 'when CollectionField.count > 0' to the guard before accessing this member"],
            ExampleBefore: "precept Example\nfield Queue as queue of string\nfield Top as string optional\nstate Draft initial\nstate Done terminal\nevent Peek\nfrom Draft on Peek -> set Top = Queue.first -> no transition",
            ExampleAfter: "precept Example\nfield Queue as queue of string\nfield Top as string optional\nstate Draft initial\nstate Done terminal\nevent Peek\nfrom Draft on Peek when Queue.count > 0 -> set Top = Queue.first -> no transition\nfrom Draft on Peek -> no transition"),
        DiagnosticCode.UnguardedCollectionMutation    => new(nameof(DiagnosticCode.UnguardedCollectionMutation),    DiagnosticStage.Type,  Severity.Error,   "'{0}' may be empty — guard with 'when {0}.count > 0' before {1}, or apply 'notempty' to the collection field",                           DiagnosticCategory.Safety,
            RelatedCodes: [DiagnosticCode.UnguardedCollectionAccess],
            FixHint: "Guard the action with 'when CollectionField.count > 0', or apply 'notempty' to the collection field declaration",
            PreventsFault: FaultCode.CollectionEmptyOnMutation,
            TriggerCondition: "A collection mutation action that requires a non-empty collection is performed without a preceding non-empty guard.",
            RecoverySteps: ["Add 'when CollectionField.count > 0' to the transition row guard before this action", "Or apply 'notempty' to the collection field declaration"],
            ExampleBefore: "precept Example\nfield Items as set of string\nstate Draft initial\nstate Done terminal\nevent RemoveItem(Tag as string)\nfrom Draft on RemoveItem -> remove Items RemoveItem.Tag -> no transition",
            ExampleAfter: "precept Example\nfield Items as set of string\nstate Draft initial\nstate Done terminal\nevent RemoveItem(Tag as string)\nfrom Draft on RemoveItem when Items.count > 0 -> remove Items RemoveItem.Tag -> no transition\nfrom Draft on RemoveItem -> no transition"),
        DiagnosticCode.NonOrderableCollectionExtreme  => new(nameof(DiagnosticCode.NonOrderableCollectionExtreme),  DiagnosticStage.Type,  Severity.Error,   "'.{1}' requires an orderable element type — '{0}' elements have no natural ordering",                                                  DiagnosticCategory.TypeSystem,
            FixHint: "Change the collection element type to an orderable type, or use .count instead",
            TriggerCondition: "A '.min' or '.max' accessor is used on a collection whose element type has no natural ordering.",
            RecoverySteps: ["Change the collection element type to an orderable type", "Or use '.count' to query the size instead"],
            ExampleBefore: "precept Example\nfield Flags as set of boolean\nrule Flags.min == true because \"all enabled\"",
            ExampleAfter: "precept Example\nfield Scores as set of number\nrule Scores.count >= 0 because \"has values\""),
        DiagnosticCode.CaseInsensitiveFieldRequiresTildeEquals => new(
            nameof(DiagnosticCode.CaseInsensitiveFieldRequiresTildeEquals),
            DiagnosticStage.Type, Severity.Error,
            "'{0}' is declared ~string (case-insensitive). Use ~= instead of == to avoid treating values like 'admin@example.com' and 'Admin@example.com' as different.",
            DiagnosticCategory.TypeSystem,
            FixHint: "Replace == with ~= for case-insensitive string comparison",
            TriggerCondition: "The '==' operator is used with a case-insensitive string field (~string) — case-insensitive equality must use '~=' instead.",
            RecoverySteps: ["Replace '==' with '~=' for case-insensitive string equality comparison"],
            ExampleBefore: "precept Example\nfield Email as ~string default \"\"\nrule Email == \"admin\" because \"must be admin\"",
            ExampleAfter: "precept Example\nfield Email as ~string default \"\"\nrule Email ~= \"admin\" because \"must be admin\""),

        // ── Type (business-domain) ───────────────────────────────────────────────
        DiagnosticCode.MaxPlacesExceeded              => new(nameof(DiagnosticCode.MaxPlacesExceeded),              DiagnosticStage.Type,  Severity.Error,   "Value has {0} decimal places, but field '{1}' allows at most {2}",                                                                     DiagnosticCategory.BusinessDomain,
            FixHint: "Increase the 'maxplaces' constraint, or use a value with fewer decimal places",
            TriggerCondition: "A decimal value assigned to a field with a 'maxplaces' constraint has more decimal places than the constraint allows.",
            RecoverySteps: ["Use a value with fewer decimal places", "Or increase the 'maxplaces' limit on the field"],
            ExampleBefore: "precept Example\nfield Price as decimal default 1.999 maxplaces 2",
            ExampleAfter: "precept Example\nfield Price as decimal default 1.99 maxplaces 2"),
        DiagnosticCode.QualifierMismatch              => new(nameof(DiagnosticCode.QualifierMismatch),              DiagnosticStage.Type,  Severity.Error,   "Value does not match the '{0}' qualifier on field '{1}'",                                                                              DiagnosticCategory.BusinessDomain,
            RelatedCodes: [DiagnosticCode.MutuallyExclusiveQualifiers],
            FixHint: "Match the qualifier value in the expression to the qualifier declared on the field",
            PreventsFault: FaultCode.QualifierMismatch,
            TriggerCondition: "A value assigned to a qualified field such as a money or quantity field uses a different qualifier than the field declares.",
            RecoverySteps: ["Ensure the value's qualifier matches the field's declared qualifier", "Convert the value before assigning it"],
            ExampleBefore: "precept Example\nfield Amount as money in 'USD' default 0\nstate Draft initial\nstate Done terminal\nevent Pay(Sum as money in 'EUR')\nfrom Draft on Pay -> set Amount = Pay.Sum -> transition Done",
            ExampleAfter: "precept Example\nfield Amount as money in 'USD' default 0\nstate Draft initial\nstate Done terminal\nevent Pay(Sum as money in 'USD')\nfrom Draft on Pay -> set Amount = Pay.Sum -> transition Done"),
        DiagnosticCode.DimensionCategoryMismatch      => new(nameof(DiagnosticCode.DimensionCategoryMismatch),      DiagnosticStage.Type,  Severity.Error,   "Dimension '{0}' does not match the declared category '{1}' on field '{2}'",                                                            DiagnosticCategory.BusinessDomain,
            RelatedCodes: [DiagnosticCode.CrossDimensionArithmetic],
            FixHint: "Use a unit whose dimension matches the declared dimension category on the field",
            TriggerCondition: "A value assigned to a dimension-qualified quantity field uses a unit from a different dimension category than the field declares.",
            RecoverySteps: ["Use a unit that belongs to the field's declared dimension category", "Check the dimension name in the field declaration and use a compatible unit"],
            ExampleBefore: "precept Example\nfield Weight as quantity of 'mass' default 0\nfield Distance as quantity of 'length' default 0\nfield Bad as quantity <- Weight + Distance",
            ExampleAfter: "precept Example\nfield Weight1 as quantity of 'mass' default 0\nfield Weight2 as quantity of 'mass' default 0\nfield Total as quantity of 'mass' <- Weight1 + Weight2"),
        DiagnosticCode.UnprovedAssignmentQualifierCompatibility => new(nameof(DiagnosticCode.UnprovedAssignmentQualifierCompatibility), DiagnosticStage.Type, Severity.Error,
            "Cannot prove the value's '{0}' qualifier satisfies field '{1}'",
            DiagnosticCategory.BusinessDomain,
            RelatedCodes: [DiagnosticCode.QualifierMismatch, DiagnosticCode.UnprovedQualifierCompatibility],
            FixHint: "Provide a source value whose required qualifier is explicitly known at compile time, or relax the field's qualifier constraint.",
            TriggerCondition: "Assignment validation reaches a qualifier axis constrained by the target field, but the source expression cannot prove a compatible qualifier value on that axis.",
            RecoverySteps: ["Use a source whose qualifier is explicitly declared on that axis", "If the source is interpolated, carry the required qualifier through a static or qualified slot", "Relax the target field's qualifier constraint if that axis should remain unconstrained"],
            ExampleBefore: "precept Example\nfield Total as money in 'USD' default '0 USD'\nfield Source as money default '1 USD'\nstate Draft initial\nstate Done terminal\nevent Apply\nfrom Draft on Apply -> set Total = Source -> transition Done",
            ExampleAfter: "precept Example\nfield Total as money in 'USD' default '0 USD'\nfield Source as money in 'USD' default '1 USD'\nstate Draft initial\nstate Done terminal\nevent Apply\nfrom Draft on Apply -> set Total = Source -> transition Done"),
        DiagnosticCode.CrossCurrencyArithmetic        => new(nameof(DiagnosticCode.CrossCurrencyArithmetic),        DiagnosticStage.Type,  Severity.Error,   "Cannot combine '{0}' ({1}) with '{2}' ({3}) — different currencies",                                                                   DiagnosticCategory.BusinessDomain,
            RelatedCodes: [DiagnosticCode.CrossDimensionArithmetic],
            FixHint: "Convert amounts to the same currency before combining them",
            TriggerCondition: "Two money or price values with different currency qualifiers are combined in arithmetic.",
            RecoverySteps: ["Convert amounts to the same currency before combining", "Use separate fields with matching currency qualifiers"],
            ExampleBefore: "precept Example\nfield USD as money in 'USD' default 0\nfield EUR as money in 'EUR' default 0\nfield Total as money in 'USD' <- USD + EUR",
            ExampleAfter: "precept Example\nfield A as money in 'USD' default 0\nfield B as money in 'USD' default 0\nfield Total as money in 'USD' <- A + B"),
        DiagnosticCode.CrossDimensionArithmetic       => new(nameof(DiagnosticCode.CrossDimensionArithmetic),       DiagnosticStage.Type,  Severity.Error,   "Cannot combine '{0}' ({1}) with '{2}' ({3}) — incompatible dimensions",                                                               DiagnosticCategory.BusinessDomain,
            RelatedCodes: [DiagnosticCode.CrossCurrencyArithmetic, DiagnosticCode.DimensionCategoryMismatch],
            FixHint: "Convert quantities to the same unit before combining them",
            TriggerCondition: "Two quantity values with incompatible dimension categories are combined in arithmetic.",
            RecoverySteps: ["Ensure both operands belong to the same dimension category before combining", "Use quantities of the same dimension in arithmetic expressions"],
            ExampleBefore: "precept Example\nfield Mass as quantity of 'mass' default 0\nfield Len as quantity of 'length' default 0\nfield Bad as quantity <- Mass + Len",
            ExampleAfter: "precept Example\nfield Mass1 as quantity of 'mass' default 0\nfield Mass2 as quantity of 'mass' default 0\nfield Total as quantity of 'mass' <- Mass1 + Mass2"),
        DiagnosticCode.DenominatorUnitMismatch        => new(nameof(DiagnosticCode.DenominatorUnitMismatch),        DiagnosticStage.Type,  Severity.Error,   "Denominator unit '{0}' does not match operand unit '{1}'",                                                                             DiagnosticCategory.BusinessDomain,
            RelatedCodes: [DiagnosticCode.DurationDenominatorMismatch, DiagnosticCode.CompoundPeriodDenominator],
            FixHint: "Use the same unit for the denominator as the operand",
            TriggerCondition: "The unit of a denominator in a division expression does not match the unit of the numerator operand.",
            RecoverySteps: ["Use the same unit for numerator and denominator so they cancel correctly", "Check that the denominator unit is compatible with the dividend's unit"],
            ExampleBefore: "precept Example\nfield Kg as quantity of 'mass' default 0\nfield Meters as quantity of 'length' default 0\nfield Rate as number <- Kg / Meters",
            ExampleAfter: "precept Example\nfield Kg1 as quantity of 'mass' default 0\nfield Kg2 as quantity of 'mass' default 1 positive\nfield Ratio as number <- Kg1 / Kg2"),
        DiagnosticCode.DurationDenominatorMismatch    => new(nameof(DiagnosticCode.DurationDenominatorMismatch),    DiagnosticStage.Type,  Severity.Error,   "Duration cannot cancel '{0}' denominator — days, weeks, months, and years have variable length",                                       DiagnosticCategory.Temporal,
            RelatedCodes: [DiagnosticCode.DenominatorUnitMismatch, DiagnosticCode.CompoundPeriodDenominator],
            FixHint: "Use only fixed-length units (hours, minutes, seconds) as duration denominators",
            TriggerCondition: "A duration is used as a denominator against an operand using a variable-length calendar unit.",
            RecoverySteps: ["Use only fixed-length units in duration division", "Or use a period field for variable-length time arithmetic"],
            ExampleBefore: "precept Example\nfield P as period of 'months' default '1 month'\nfield D as duration default '30 days'\nfield Rate as number <- P / D",
            ExampleAfter: "precept Example\nfield D1 as duration default '60 minutes'\nfield D2 as duration default '30 minutes'\nfield Ratio as number <- D1 / D2"),
        DiagnosticCode.CompoundPeriodDenominator      => new(nameof(DiagnosticCode.CompoundPeriodDenominator),      DiagnosticStage.Type,  Severity.Error,   "Compound period '{0}' cannot cancel single-unit denominator '{1}'",                                                                    DiagnosticCategory.Temporal,
            RelatedCodes: [DiagnosticCode.DenominatorUnitMismatch, DiagnosticCode.DurationDenominatorMismatch],
            FixHint: "Use a single-unit period instead of a compound period as the denominator",
            TriggerCondition: "A compound period with multiple unit components is used as a denominator in division.",
            RecoverySteps: ["Use a single-unit period as the denominator", "Or convert to a single-unit period before dividing"],
            ExampleBefore: "precept Example\nfield P1 as period default '2 years'\nfield P2 as period default '1 year + 2 months'\nfield Rate as number <- P1 / P2",
            ExampleAfter: "precept Example\nfield P1 as period of 'years' default '2 years'\nfield P2 as period of 'years' default '1 year'\nfield Rate as number <- P1 / P2"),
        DiagnosticCode.InvalidUnitString              => new(nameof(DiagnosticCode.InvalidUnitString),              DiagnosticStage.Type,  Severity.Error,   "'{0}' is not a valid unit",                                                                                                            DiagnosticCategory.BusinessDomain,
            RelatedCodes: [DiagnosticCode.InvalidCurrencyCode, DiagnosticCode.InvalidDimensionString],
            FixHint: "Use a recognized unit identifier, such as 'kg', 'miles', or 'liters'",
            TriggerCondition: "A typed constant used as a unit qualifier is not recognized as a valid unit identifier in Precept's unit catalog.",
            RecoverySteps: ["Use a recognized unit identifier such as 'kg', 'miles', 'liters', or 'meters'", "Check spelling and capitalization"],
            ExampleBefore: "precept Example\nfield Weight as quantity in 'kilogrammes'",
            ExampleAfter: "precept Example\nfield Weight as quantity in 'kg'"),
        DiagnosticCode.InvalidCurrencyCode            => new(nameof(DiagnosticCode.InvalidCurrencyCode),            DiagnosticStage.Type,  Severity.Error,   "'{0}' is not a recognized ISO 4217 currency code",                                                                                     DiagnosticCategory.BusinessDomain,
            RelatedCodes: [DiagnosticCode.InvalidUnitString, DiagnosticCode.InvalidDimensionString],
            FixHint: "Use a valid ISO 4217 currency code, such as 'USD', 'EUR', or 'GBP'",
            TriggerCondition: "A typed constant used as a currency qualifier is not a recognized ISO 4217 currency code.",
            RecoverySteps: ["Use a valid ISO 4217 three-letter currency code such as 'USD', 'EUR', or 'GBP'"],
            ExampleBefore: "precept Example\nfield Amount as money in 'DOLLARS'",
            ExampleAfter: "precept Example\nfield Amount as money in 'USD'"),
        DiagnosticCode.InvalidDimensionString         => new(nameof(DiagnosticCode.InvalidDimensionString),         DiagnosticStage.Type,  Severity.Error,   "'{0}' is not a recognized dimension",                                                                                                  DiagnosticCategory.BusinessDomain,
            RelatedCodes: [DiagnosticCode.InvalidUnitString, DiagnosticCode.InvalidCurrencyCode],
            FixHint: "Use a recognized dimension identifier, such as 'length', 'mass', or 'time'",
            TriggerCondition: "A typed constant used as a dimension qualifier is not a recognized dimension category name in Precept's dimension catalog.",
            RecoverySteps: ["Use a recognized dimension name such as 'length', 'mass', 'time', 'area', or 'volume'"],
            ExampleBefore: "precept Example\nfield Weight as quantity of 'heaviness'",
            ExampleAfter: "precept Example\nfield Weight as quantity of 'mass'"),

        // ── Runtime / value safety ────────────────────────────────────────────────
        DiagnosticCode.NumericOverflow                => new(nameof(DiagnosticCode.NumericOverflow),                DiagnosticStage.Type,  Severity.Error,   "Numeric computation exceeded the representable range on field '{0}'",                                                                  DiagnosticCategory.Safety,
            FixHint: "Reduce the magnitude of operands, or widen the field type to number",
            PreventsFault: FaultCode.NumericOverflow,
            TriggerCondition: "A numeric computation or constant value exceeds the representable range for the field's declared type.",
            RecoverySteps: ["Reduce the magnitude of the operands or constant value", "Or widen the field type to 'number' if a larger range is needed"],
            ExampleBefore: "precept Example\nfield X as integer default 9999999999999999999",
            ExampleAfter: "precept Example\nfield X as integer default 0"),
        DiagnosticCode.OutOfRange                     => new(nameof(DiagnosticCode.OutOfRange),                     DiagnosticStage.Type,  Severity.Error,   "Value is outside the declared bounds for field '{0}'",                                                                                 DiagnosticCategory.Safety,
            RelatedCodes: [DiagnosticCode.InvalidModifierBounds],
            FixHint: "Ensure assigned values satisfy the field's min/max constraints, or widen the bounds",
            PreventsFault: FaultCode.OutOfRange,
            TriggerCondition: "A value assigned to a field violates the field's 'min' or 'max' constraint.",
            RecoverySteps: ["Ensure assigned values satisfy the field's declared bounds", "Or adjust the 'min' or 'max' constraints"],
            ExampleBefore: "precept Example\nfield X as number default 150 min 0 max 100",
            ExampleAfter: "precept Example\nfield X as number default 50 min 0 max 100"),

        // ── Graph ─────────────────────────────────────────────────────────────────
        DiagnosticCode.UnreachableState               => new(nameof(DiagnosticCode.UnreachableState),               DiagnosticStage.Graph, Severity.Warning, "State '{0}' is unreachable from initial state '{1}'",                                                                                  DiagnosticCategory.Structure,
            RelatedCodes: [DiagnosticCode.NoInitialState],
            FixHint: "Add a transition to this state, or remove it if it is no longer needed",
            TriggerCondition: "A declared state has no incoming path from the initial state.",
            RecoverySteps: ["Add a transition leading to this state from a reachable state", "Or remove the state if it is no longer needed"],
            ExampleBefore: "precept Example\nstate Draft initial\nstate Review\nstate Done terminal\nevent Complete\nfrom Draft on Complete -> transition Done",
            ExampleAfter: "precept Example\nstate Draft initial\nstate Done terminal\nevent Complete\nfrom Draft on Complete -> transition Done"),
        DiagnosticCode.UnhandledEvent                 => new(nameof(DiagnosticCode.UnhandledEvent),                 DiagnosticStage.Graph, Severity.Warning, "Event '{0}' has no transition rows in any state — it can never be fired successfully",                                       DiagnosticCategory.Structure,
            FixHint: "Add at least one transition row that handles this event, or remove the event declaration",
            TriggerCondition: "An event is declared but has no transition rows in any state.",
            RecoverySteps: ["Add at least one transition row that handles this event", "Or remove the event declaration if it is not needed"],
            ExampleBefore: "precept Example\nstate Draft initial\nstate Done terminal\nevent Complete\nevent Cancel\nfrom Draft on Complete -> transition Done",
            ExampleAfter: "precept Example\nstate Draft initial\nstate Done terminal\nevent Complete\nfrom Draft on Complete -> transition Done"),
