        // ── Type (temporal — period qualifier validation) ─────────────────────
        DiagnosticCode.InvalidTemporalDimensionString => new(nameof(DiagnosticCode.InvalidTemporalDimensionString), DiagnosticStage.Type, Severity.Error,
